// test/integration/health-monitor.test.ts
import { describe, it, expect, beforeEach, afterEach, vi } from "vitest";
import * as health from "@zana/core/src/api/health-monitor";
import { bus } from "@zana/core/src/events/bus";

describe("health-monitor", () => {
  afterEach(() => {
    health.stop();
  });

  describe("stale agent detection", () => {
    it("emits event for agent inactive > 30min", () => {
      const mockAgents = [
        {
          id: "stale",
          state: "running",
          lastActivityAt: new Date(Date.now() - 31 * 60 * 1000).toISOString(),
          profileName: "test",
        },
      ];

      let emitted = false;
      bus.on("health:stale-agent", () => { emitted = true; });

      health.init(() => mockAgents);
      health.check();

      expect(emitted).toBe(true);
    });

    it("ignores terminated agents", () => {
      const mockAgents = [
        {
          id: "terminated",
          state: "terminated",
          lastActivityAt: new Date(Date.now() - 60 * 60 * 1000).toISOString(),
        },
      ];

      let emitted = false;
      bus.on("health:stale-agent", () => { emitted = true; });

      health.init(() => mockAgents);
      health.check();

      expect(emitted).toBe(false);
    });

    it("uses spawnedAt if lastActivityAt missing", () => {
      const mockAgents = [
        {
          id: "new",
          state: "running",
          spawnedAt: new Date(Date.now() - 1000).toISOString(),
        },
      ];

      let emitted = false;
      bus.on("health:stale-agent", () => { emitted = true; });

      health.init(() => mockAgents);
      health.check();

      expect(emitted).toBe(false);
    });
  });

  describe("memory monitoring", () => {
    it("emits warning when heap exceeds threshold", () => {
      // Mock high memory usage
      const originalUsage = process.memoryUsage;
      process.memoryUsage = () => ({ heapUsed: 600 * 1024 * 1024 }) as any;

      let emitted = false;
      bus.on("health:memory-warning", () => { emitted = true; });

      health.init(() => []);
      health.check();

      expect(emitted).toBe(true);
      process.memoryUsage = originalUsage;
    });

    it("does not emit when heap below threshold", () => {
      let emitted = false;
      bus.on("health:memory-warning", () => { emitted = true; });

      health.init(() => []);
      health.check();

      expect(emitted).toBe(false);
    });
  });

  describe("status reporting", () => {
    it("returns system status", () => {
      const mockAgents = [
        { id: "a1", state: "running" },
        { id: "a2", state: "terminated" },
      ];

      const status = health.getStatus(() => mockAgents);

      expect(status.status).toBe("ok");
      expect(status.agents.total).toBe(2);
      expect(status.agents.active).toBe(1);
      expect(status.memory.heapUsed).toBeGreaterThan(0);
      expect(status.pid).toBe(process.pid);
    });
  });

  describe("lifecycle", () => {
    it("starts periodic checks on init", async () => {
      const checkSpy = vi.spyOn(health, "check");
      health.init(() => []);

      await new Promise(r => setTimeout(r, 65000)); // Wait > 60s interval

      expect(checkSpy).toHaveBeenCalled();
    });

    it("stops periodic checks", () => {
      health.init(() => []);
      health.stop();
      // Verify interval cleared
    });
  });
});
